import{_ as p}from"./chunks/plugin-vue_export-helper.DlAUqK2U.js";import{B as i,c as s,f as A,q as n,D as a,O as r,j as l,g as e,k as E,X as B}from"./chunks/runtime-core.esm-bundler.DoiTk7Jm.js";const C=JSON.parse('{"title":"AI变成基础设施之后，什么最值钱","description":"","frontmatter":{},"headers":[],"relativePath":"column/AIFuture/趋势观察/AI变成基础设施之后，什么最值钱.md","filePath":"column/AIFuture/趋势观察/AI变成基础设施之后，什么最值钱.md","lastUpdated":1782975799000}'),u={name:"column/AIFuture/趋势观察/AI变成基础设施之后，什么最值钱.md"};function _(I,t,h,m,g,q){const d=i("ArticleMetadata"),o=i("Mermaid");return A(),s("div",null,[t[3]||(t[3]=n("h1",{id:"ai变成基础设施之后-什么最值钱",tabindex:"-1"},[e("AI变成基础设施之后，什么最值钱 "),n("a",{class:"header-anchor",href:"#ai变成基础设施之后-什么最值钱","aria-label":'Permalink to "AI变成基础设施之后，什么最值钱"'},"​")],-1)),a(d),t[4]||(t[4]=r('<p>有三件事正在同时发生：</p><ol><li>模型能力越来越强，也越来越便宜</li><li>各家模型之间的差距越来越小</li><li>开源模型在某些场景下已经追平甚至超过了闭源模型</li></ol><p>当这三件事叠加在一起，一个结论就变得很清晰了：<strong>AI 正在从&quot;核心技术&quot;变成&quot;基础设施&quot;。就像电、云服务、带宽一样——重要，但不再是差异化来源。</strong></p><p>那问题来了：当 AI 变成水电煤一样的底座之后，上面什么东西最值钱？</p><h2 id="回顾一下历史" tabindex="-1">回顾一下历史 <a class="header-anchor" href="#回顾一下历史" aria-label="Permalink to &quot;回顾一下历史&quot;">​</a></h2><p>每次基础设施层的成熟，都会在上层催生新的稀缺资源。</p><p><strong>云计算时代</strong>：当算力和存储变成按需购买之后，最值钱的变成了数据——谁有数据，谁能用数据训练模型、做推荐、打标签。</p><p><strong>移动互联网时代</strong>：当开发一个 App 的门槛降到极低之后，最值钱的变成了注意力——谁能抢占用户的使用时长。</p><p><strong>AI 时代呢？</strong></p><p>我的判断是：<strong>最值钱的三样东西是专有数据、领域知识、和对用户的深度理解。</strong></p>',10)),(A(),l(B,null,{default:E(()=>[a(o,{id:"mermaid-47",class:"mermaid",graph:"flowchart%20TD%0A%20%20A%5B%22AI%20%E5%9F%BA%E7%A1%80%E8%AE%BE%E6%96%BD%E5%B1%82%EF%BC%88%E6%A8%A1%E5%9E%8B%2F%E7%AE%97%E5%8A%9B%EF%BC%89%22%5D%20--%3E%20B%5B%22%E8%B6%8B%E4%BA%8E%E5%90%8C%E8%B4%A8%E5%8C%96%22%5D%0A%20%20B%20--%3E%20C%5B%22%E5%B7%AE%E5%BC%82%E5%8C%96%E4%B8%8A%E7%A7%BB%E5%88%B0%E5%BA%94%E7%94%A8%E5%B1%82%22%5D%0A%20%20C%20--%3E%20D%5B%22%E4%B8%93%E6%9C%89%E6%95%B0%E6%8D%AE%22%5D%0A%20%20C%20--%3E%20E%5B%22%E9%A2%86%E5%9F%9F%E7%9F%A5%E8%AF%86%22%5D%0A%20%20C%20--%3E%20F%5B%22%E7%94%A8%E6%88%B7%E7%90%86%E8%A7%A3%22%5D%0A"})]),fallback:E(()=>[...t[0]||(t[0]=[e(" Loading... ",-1)])]),_:1})),t[5]||(t[5]=r('<h2 id="专有数据-你有别人没有的东西" tabindex="-1">专有数据：你有别人没有的东西 <a class="header-anchor" href="#专有数据-你有别人没有的东西" aria-label="Permalink to &quot;专有数据：你有别人没有的东西&quot;">​</a></h2><p>这件事说起来简单，但大多数人低估了它的价值。</p><p>通用的 AI 模型是用互联网的公开数据训练的。它能写诗、能总结文章、能解释概念——这些能力对所有人都是平等的。</p><p>但它不知道：</p><ul><li>你们公司的报销流程上次是什么时候改的</li><li>你的客户 A 对 B 类合同条款特别敏感</li><li>你们团队在某个技术选型上踩过哪些坑</li><li>过去三年你们产品被用户投诉最多的问题是什么</li></ul><p><strong>这些数据长在你的业务里，别人拿不走，模型也自带不了。</strong></p><p>把专有数据组织好、清洗好、持续更新，这件事在 AI 时代的价值会被重估。以前你整理文档是为了给人看，以后你整理文档是为了给 AI 看——后者的 ROI 可能会高出一个量级。</p>',7)),(A(),l(B,null,{default:E(()=>[a(o,{id:"mermaid-88",class:"mermaid",graph:"flowchart%20LR%0A%20%20A%5B%22%E4%B8%9A%E5%8A%A1%E4%BA%A7%E7%94%9F%E6%95%B0%E6%8D%AE%22%5D%20--%3E%20B%5B%22%E6%95%B0%E6%8D%AE%E6%B8%85%E6%B4%97%E6%B2%BB%E7%90%86%22%5D%0A%20%20B%20--%3E%20C%5B%22%E5%96%82%E7%BB%99%20AI%22%5D%0A%20%20C%20--%3E%20D%5B%22AI%20%E8%BE%85%E5%8A%A9%E4%B8%9A%E5%8A%A1%22%5D%0A%20%20D%20--%3E%20A%0A"})]),fallback:E(()=>[...t[1]||(t[1]=[e(" Loading... ",-1)])]),_:1})),t[6]||(t[6]=r('<p>这是一个飞轮。数据越好，AI 越强；AI 越强，业务越依赖；业务越依赖，数据越好。</p><h2 id="领域知识-懂一个行业的厚度" tabindex="-1">领域知识：懂一个行业的厚度 <a class="header-anchor" href="#领域知识-懂一个行业的厚度" aria-label="Permalink to &quot;领域知识：懂一个行业的厚度&quot;">​</a></h2><p>用 AI 写一篇通用的营销文案，十秒钟搞定。</p><p>用 AI 写一篇能过药监局审批的药品说明文案，难的不是 AI 不会写，而是你没法一次性把&quot;什么能说、什么不能说、什么必须说、用什么词不能说&quot;这些规则喂给它。</p><p><strong>这些规则不在互联网上，在行业里的人脑子里。</strong></p><p>领域知识包括：</p><ul><li>成文的法规和标准</li><li>不成文的惯例和潜规则</li><li>只有踩过坑才知道的边界条件</li><li>跨部门协作中形成的共识</li></ul><p>AI 能加速这些知识的传播和应用，但它不能替你&quot;拥有&quot;这些知识。</p><p><strong>未来最贵的人，是能把一个行业的隐性知识显性化、结构化的人。</strong> 他们写的不再是&quot;怎么做&quot;的操作手册，而是&quot;AI 怎么理解这个行业&quot;的规则书。</p><h2 id="用户理解-知道用户真正要什么" tabindex="-1">用户理解：知道用户真正要什么 <a class="header-anchor" href="#用户理解-知道用户真正要什么" aria-label="Permalink to &quot;用户理解：知道用户真正要什么&quot;">​</a></h2><p>这可能是最被低估的东西。</p><p>AI 能帮你生成 100 个产品文案版本，但它不知道你的用户看了哪个会下单。</p><p>AI 能帮你分析用户反馈，但它不知道哪条反馈背后藏着用户不会说出口的真正需求。</p><p><strong>用户信任是一点一点攒出来的。</strong> 这件事没有捷径，再强的模型也替不了。</p><p>在 AI 时代，理解用户的壁垒反而更高了——因为你的竞争对手也能用 AI 生成内容、做客服、写方案。当效率工具拉平之后，谁能更懂用户，谁就能赢。</p><h2 id="那什么在贬值" tabindex="-1">那什么在贬值？ <a class="header-anchor" href="#那什么在贬值" aria-label="Permalink to &quot;那什么在贬值？&quot;">​</a></h2><p>说完值钱的，也说说在贬值的。没有焦虑的意思，纯聊趋势：</p><table tabindex="0"><thead><tr><th>在贬值</th><th>为什么</th><th>替代者</th></tr></thead><tbody><tr><td>纯执行型编程</td><td>AI 写 CRUD 又快又好</td><td>AI 编码助手</td></tr><tr><td>通用文案写作</td><td>模型出稿质量已经够用</td><td>ChatGPT / Claude</td></tr><tr><td>信息搬运类工作</td><td>从 A 系统抄到 B 系统</td><td>Agent + API</td></tr><tr><td>初级翻译</td><td>模型翻译质量接近人工</td><td>翻译类 AI</td></tr><tr><td>模板化设计排版</td><td>模型生成设计稿</td><td>AI 设计工具</td></tr></tbody></table><p>不是说这些工作会消失，而是<strong>做这些事的人需要往价值链上游走</strong>。纯执行不值钱了，能定义&quot;做什么&quot;和&quot;为什么做&quot;才值钱。</p><h2 id="如果你现在想布局" tabindex="-1">如果你现在想布局 <a class="header-anchor" href="#如果你现在想布局" aria-label="Permalink to &quot;如果你现在想布局&quot;">​</a></h2>',20)),(A(),l(B,null,{default:E(()=>[a(o,{id:"mermaid-237",class:"mermaid",graph:"mindmap%0A%20%20root((AI%E6%97%B6%E4%BB%A3%E5%B8%83%E5%B1%80%E6%96%B9%E5%90%91))%0A%20%20%20%20%E7%A7%AF%E7%B4%AF%E6%95%B0%E6%8D%AE%0A%20%20%20%20%20%20%E6%95%B4%E7%90%86%E8%87%AA%E6%9C%89%E6%95%B0%E6%8D%AE%0A%20%20%20%20%20%20%E5%BB%BA%E7%AB%8B%E5%8F%8D%E9%A6%88%E9%97%AD%E7%8E%AF%0A%20%20%20%20%20%20%E6%8C%81%E7%BB%AD%E6%B8%85%E6%B4%97%E6%9B%B4%E6%96%B0%0A%20%20%20%20%E6%B7%B1%E8%80%95%E8%A1%8C%E4%B8%9A%0A%20%20%20%20%20%20%E9%80%89%E6%8B%A9%E4%B8%80%E4%B8%AA%E5%9E%82%E7%9B%B4%E9%A2%86%E5%9F%9F%0A%20%20%20%20%20%20%E5%90%83%E9%80%8F%E4%B8%9A%E5%8A%A1%E8%A7%84%E5%88%99%0A%20%20%20%20%20%20%E6%8A%8A%E9%9A%90%E6%80%A7%E7%9F%A5%E8%AF%86%E7%BB%93%E6%9E%84%E5%8C%96%0A%20%20%20%20%E7%90%86%E8%A7%A3%E7%94%A8%E6%88%B7%0A%20%20%20%20%20%20%E7%A6%BB%E7%94%A8%E6%88%B7%E8%BF%91%E4%B8%80%E7%82%B9%0A%20%20%20%20%20%20%E8%A7%82%E5%AF%9F%E7%9C%9F%E5%AE%9E%E4%BD%BF%E7%94%A8%E5%9C%BA%E6%99%AF%0A%20%20%20%20%20%20%E8%A7%A3%E5%86%B3%E5%85%B7%E4%BD%93%E8%80%8C%E9%9D%9E%E6%8A%BD%E8%B1%A1%E7%9A%84%E9%97%AE%E9%A2%98%0A%20%20%20%20%E6%8B%A5%E6%8A%B1%E5%8F%98%E5%8C%96%0A%20%20%20%20%20%20%E4%B8%8D%E6%8E%92%E6%96%A5%E6%96%B0%E5%B7%A5%E5%85%B7%0A%20%20%20%20%20%20%E4%BF%9D%E6%8C%81%E5%AD%A6%E4%B9%A0%E4%B9%A0%E6%83%AF%0A%20%20%20%20%20%20%E5%85%B3%E6%B3%A8%E5%BA%94%E7%94%A8%E5%B1%82%E8%80%8C%E9%9D%9E%E6%A8%A1%E5%9E%8B%E5%B1%82%0A"})]),fallback:E(()=>[...t[2]||(t[2]=[e(" Loading... ",-1)])]),_:1})),t[7]||(t[7]=r('<h2 id="几句掏心窝子的话" tabindex="-1">几句掏心窝子的话 <a class="header-anchor" href="#几句掏心窝子的话" aria-label="Permalink to &quot;几句掏心窝子的话&quot;">​</a></h2><ol><li><p><strong>不要焦虑&quot;AI 会不会替代我&quot;。</strong> 焦虑的是不知道自己能提供什么独特价值的人。如果你知道自己擅长什么、积累了什么、能解决什么具体问题，AI 是你的杠杆，不是你的对手。</p></li><li><p><strong>数据的积累是慢功夫，但也是最稳的护城河。</strong> 今天开始整理，一年后回头看，你会感谢自己。</p></li><li><p><strong>通用能力在贬值，垂直能力在升值。</strong> 与其成为一个&quot;什么都会一点的 AI 通才&quot;，不如成为一个&quot;在这个领域 AI 也替代不了&quot;的专家。</p></li></ol><blockquote><p>当所有人都有同样的 AI 时，你唯一拉不开差距的就是 AI 本身。真正拉开差距的，是你有而别人没有的那部分。</p></blockquote><hr><p><em>延伸阅读</em></p><ul><li><a href="https://a16z.com/ai-infrastructure/" target="_blank" rel="noreferrer">a16z：The Infrastructure-as-a-Service Era for AI</a></li><li><a href="https://www.ben-evans.com/" target="_blank" rel="noreferrer">Benedict Evans：AI and the automation of work</a></li><li><a href="https://stratechery.com/" target="_blank" rel="noreferrer">Stratechery：The AI Unbundling</a></li></ul>',6))])}const c=p(u,[["render",_]]);export{C as __pageData,c as default};
